namespace UniversityCourseCatalog.Services;

public class CourseCatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CourseCatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, quantities, shapes, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENGL", Description = "Study of literature, writing, and the English language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and their impact on human civilization." }
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 papers and holds three patents in natural language processing.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. James Rodriguez", Title = "Associate Professor", Bio = "Dr. Rodriguez focuses on software engineering and distributed systems. He spent ten years in industry at major tech companies before joining academia.", Email = "j.rodriguez@university.edu" },
            new() { Id = 3, Name = "Dr. Emily Watson", Title = "Professor", Bio = "Dr. Watson is a number theorist with a passion for teaching calculus and linear algebra. She received the Distinguished Teaching Award in 2022.", Email = "e.watson@university.edu" },
            new() { Id = 4, Name = "Dr. Michael Park", Title = "Assistant Professor", Bio = "Dr. Park researches quantum computing and condensed matter physics. He completed his postdoc at CERN.", Email = "m.park@university.edu" },
            new() { Id = 5, Name = "Dr. Lisa Thompson", Title = "Professor", Bio = "Dr. Thompson is an award-winning author and literary critic specializing in modern American fiction and creative writing.", Email = "l.thompson@university.edu" },
            new() { Id = 6, Name = "Dr. Robert Kim", Title = "Associate Professor", Bio = "Dr. Kim is a historian of early modern Europe with expertise in the Renaissance and Reformation periods.", Email = "r.kim@university.edu" },
            new() { Id = 7, Name = "Dr. Anna Martinez", Title = "Professor", Bio = "Dr. Martinez specializes in applied mathematics and statistical modeling, with applications in climate science.", Email = "a.martinez@university.edu" }
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Computer Science", Description = "An introductory course covering the fundamentals of programming, data structures, and algorithmic thinking. Students will learn to write programs in Python and gain exposure to core CS concepts.", Credits = 3, Schedule = "MWF 10:00-10:50 AM", Location = "Room 201, Science Building", MaxEnrollment = 120, CurrentEnrollment = 98, IsFeatured = true, DepartmentId = 1, InstructorId = 1 },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures and Algorithms", Description = "A deep dive into fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques (sorting, searching, dynamic programming).", Credits = 4, Schedule = "TTh 1:00-2:15 PM", Location = "Room 305, Engineering Hall", MaxEnrollment = 60, CurrentEnrollment = 55, IsFeatured = false, DepartmentId = 1, InstructorId = 2 },
            new() { Id = 3, Code = "CS 350", Title = "Artificial Intelligence", Description = "Explores the principles and techniques of AI including search, knowledge representation, machine learning, and neural networks.", Credits = 3, Schedule = "MWF 2:00-2:50 PM", Location = "Room 110, Tech Center", MaxEnrollment = 45, CurrentEnrollment = 44, IsFeatured = true, DepartmentId = 1, InstructorId = 1 },

            // Mathematics
            new() { Id = 4, Code = "MATH 101", Title = "Calculus I", Description = "Introduction to differential calculus covering limits, continuity, derivatives, and applications of the derivative to related rates and optimization problems.", Credits = 4, Schedule = "MWF 9:00-9:50 AM", Location = "Room 100, Math Hall", MaxEnrollment = 150, CurrentEnrollment = 130, IsFeatured = true, DepartmentId = 2, InstructorId = 3 },
            new() { Id = 5, Code = "MATH 201", Title = "Linear Algebra", Description = "Study of vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to systems of linear equations.", Credits = 3, Schedule = "TTh 10:30-11:45 AM", Location = "Room 102, Math Hall", MaxEnrollment = 80, CurrentEnrollment = 62, IsFeatured = false, DepartmentId = 2, InstructorId = 3 },
            new() { Id = 6, Code = "MATH 310", Title = "Probability and Statistics", Description = "Introduction to probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "MWF 11:00-11:50 AM", Location = "Room 104, Math Hall", MaxEnrollment = 70, CurrentEnrollment = 58, IsFeatured = false, DepartmentId = 2, InstructorId = 7 },

            // Physics
            new() { Id = 7, Code = "PHYS 101", Title = "General Physics I", Description = "Introduction to mechanics, thermodynamics, and waves. Covers Newton's laws, energy, momentum, rotational motion, and oscillations.", Credits = 4, Schedule = "MWF 1:00-1:50 PM", Location = "Room 200, Science Building", MaxEnrollment = 100, CurrentEnrollment = 78, IsFeatured = false, DepartmentId = 3, InstructorId = 4 },
            new() { Id = 8, Code = "PHYS 301", Title = "Quantum Mechanics", Description = "Introduction to quantum theory including wave-particle duality, the Schrödinger equation, quantum states, and measurement.", Credits = 3, Schedule = "TTh 3:00-4:15 PM", Location = "Room 210, Science Building", MaxEnrollment = 35, CurrentEnrollment = 28, IsFeatured = true, DepartmentId = 3, InstructorId = 4 },

            // English
            new() { Id = 9, Code = "ENGL 101", Title = "English Composition", Description = "Develop effective writing skills through expository and argumentative essays. Emphasis on critical thinking, research, and revision.", Credits = 3, Schedule = "MWF 10:00-10:50 AM", Location = "Room 301, Humanities Building", MaxEnrollment = 30, CurrentEnrollment = 25, IsFeatured = false, DepartmentId = 4, InstructorId = 5 },
            new() { Id = 10, Code = "ENGL 220", Title = "American Literature", Description = "Survey of major works of American literature from the colonial period to the present, exploring themes of identity, freedom, and the American experience.", Credits = 3, Schedule = "TTh 11:00 AM-12:15 PM", Location = "Room 303, Humanities Building", MaxEnrollment = 35, CurrentEnrollment = 30, IsFeatured = false, DepartmentId = 4, InstructorId = 5 },

            // History
            new() { Id = 11, Code = "HIST 101", Title = "World History I", Description = "Survey of world history from ancient civilizations through the early modern period, examining political, social, and cultural developments.", Credits = 3, Schedule = "MWF 9:00-9:50 AM", Location = "Room 400, Liberal Arts Building", MaxEnrollment = 80, CurrentEnrollment = 65, IsFeatured = false, DepartmentId = 5, InstructorId = 6 },
            new() { Id = 12, Code = "HIST 250", Title = "The Renaissance and Reformation", Description = "An in-depth study of European cultural, religious, and political transformation from the 14th to the 17th century.", Credits = 3, Schedule = "TTh 2:00-3:15 PM", Location = "Room 402, Liberal Arts Building", MaxEnrollment = 40, CurrentEnrollment = 32, IsFeatured = false, DepartmentId = 5, InstructorId = 6 }
        };

        // Wire up navigation properties
        foreach (var course in _courses)
        {
            course.Department = _departments.First(d => d.Id == course.DepartmentId);
            course.Instructor = _instructors.First(i => i.Id == course.InstructorId);
        }
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public EnrollmentResult SubmitEnrollment(EnrollmentRequest request)
    {
        var course = GetCourse(request.CourseId);
        if (course == null)
        {
            return new EnrollmentResult { Success = false, Message = "Course not found." };
        }

        if (course.CurrentEnrollment >= course.MaxEnrollment)
        {
            return new EnrollmentResult
            {
                Success = false,
                Message = $"Sorry, {course.Title} is full.",
                CourseName = course.Title,
                StudentName = request.StudentName,
                StudentId = request.StudentId
            };
        }

        course.CurrentEnrollment++;

        return new EnrollmentResult
        {
            Success = true,
            Message = $"Successfully enrolled in {course.Code} - {course.Title}!",
            CourseName = $"{course.Code} - {course.Title}",
            StudentName = request.StudentName,
            StudentId = request.StudentId
        };
    }
}

