        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public EnrollmentResult SubmitEnrollment(EnrollmentRequest request)
    {
        var course = GetCourse(request.CourseId);
        if (course == null)
        {
            return new EnrollmentResult { Success = false, Message = "Course not found." };
        }

        if (course.CurrentEnrollment >= course.MaxEnrollment)
        {
            return new EnrollmentResult
            {
                Success = false,
                Message = $"Sorry, {course.Title} is full.",
                CourseName = course.Title,
                StudentName = request.StudentName,
                StudentId = request.StudentId
            };
        }

        course.CurrentEnrollment++;

        return new EnrollmentResult
        {
            Success = true,
            Message = $"Successfully enrolled in {course.Code} - {course.Title}!",
            CourseName = $"{course.Code} - {course.Title}",
            StudentName = request.StudentName,
            StudentId = request.StudentId
        };
    }
}

