arguments.file_text:
@page "/courses"
@inject CourseCatalogService CatalogService

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1 class="mb-4">Course Catalog</h1>

<form method="get" action="/courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <label for="search" class="form-label">Search</label>
        <input type="text" class="form-control" id="search" name="search" value="@Search" placeholder="Search by name, code, or description..." />
    </div>
    <div class="col-md-4">
        <label for="department" class="form-label">Department</label>
        <select class="form-select" id="department" name="department">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(Department == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-end">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Schedule</th>
                    <th>Enrollment</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    <tr>
                        <td>@course.Code</td>
                        <td>@course.Title</td>
                        <td>@course.Department.Name</td>
                        <td>@course.Credits</td>
                        <td>@course.Schedule</td>
                        <td>
                            @course.CurrentEnrollment / @course.MaxEnrollment
                            @if (course.CurrentEnrollment >= course.MaxEnrollment)
                            {
                                <span class="badge bg-danger">Full</span>
                            }
                            else
                            {
                                <span class="badge bg-success">Open</span>
                            }
                        </td>
                        <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? Department { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        courses = CatalogService.GetCourses(Search, Department);
    }
}

@page "/enroll"
@inject CourseCatalogService CatalogService

<PageTitle>Enroll - University Course Catalog</PageTitle>

<h1 class="mb-4">Course Enrollment</h1>

@if (result is not null)
{
    <div class="alert @(result.Success ? "alert-success" : "alert-danger")">
        <h4>@(result.Success ? "Enrollment Confirmed!" : "Enrollment Failed")</h4>
        <p>@result.Message</p>
        @if (result.Success)
        {
            <ul class="mb-0">
                <li><strong>Student:</strong> @result.StudentName (@result.StudentId)</li>
                <li><strong>Course:</strong> @result.CourseName</li>
            </ul>
        }
    </div>
    <a href="/courses" class="btn btn-primary">Browse More Courses</a>
}
else
{
    <EditForm method="post" FormName="enrollment" Model="Model" OnValidSubmit="HandleSubmit">
        <AntiforgeryToken />
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
            <ValidationMessage For="() => Model.StudentName" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" />
            <ValidationMessage For="() => Model.StudentId" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                <option value="0">-- Select a Course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.Code - @course.Title (@course.Credits cr.)</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment</button>
        <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private List<Course> courses = new();
    private EnrollmentResult? result;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        result = CatalogService.SubmitEnrollment(Model);
    }
}

